subprograms.code:
function Get_Quoted
         (  Source  : String;
            Pointer : access Integer;
            Mark    : Character := '"'
         )  return String

procedure Put_Quoted
          (  Destination : in out String;
             Pointer     : in out Integer;
             Text        : String;
             Mark        : Character := '"';
             Field       : Natural   := 0;
             Justify     : Alignment := Left;
             Fill        : Character := ' '
          )
